-- ============================================
-- 082: Fix activity.create input_schema for AI-generated title flow
-- - Remove title from required (title is AI-generated by refiner from description_raw)
-- - Add description_raw to properties
-- - Change activity_date format to "date" (date picker sends YYYY-MM-DD)
-- ============================================

-- media_keys items: accept string OR object (file upload sends {s3Key, originalFilename, ...})
UPDATE option_definitions
SET input_schema = '{
  "type": "object",
  "properties": {
    "description_raw": {"type": "string"},
    "title": {"type": "string"},
    "description": {"type": "string"},
    "activity_date": {"type": "string", "format": "date"},
    "location": {"type": "string"},
    "status": {"type": "string", "enum": ["planned", "in_progress", "completed", "cancelled"]},
    "visibility": {"type": "string", "enum": ["private", "team", "public"]},
    "tags": {"type": "array", "items": {"type": "string"}},
    "media_keys": {"type": "array", "items": {"oneOf": [{"type": "string"}, {"type": "object"}]}},
    "participants": {"type": "array"}
  },
  "required": ["description_raw"]
}'::jsonb
WHERE id = 'activity.create';
